def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        prs = Presentation(modified_ppt_path)

        target_text = "Philippine History: An Educational Overview"
        found_in_subtitle_position = False

        # Check first slide (most likely location for title/subtitle)
        if len(prs.slides) > 0:
            slide = prs.slides[0]

            # Look for title and subtitle layout
            title_shape = None
            subtitle_shape = None

            for shape in slide.shapes:
                if hasattr(shape, 'text') and shape.text.strip():
                    # Check if this could be a title (typically larger, higher on slide)
                    if shape.top < slide.shapes[0].height // 3:  # Upper third of slide
                        if len(shape.text.strip()) > 5:  # Reasonable title length
                            title_shape = shape
                    # Check if this is our target subtitle text
                    elif shape.text.strip() == target_text:
                        subtitle_shape = shape

            # Verify subtitle is positioned below title
            if subtitle_shape and title_shape:
                if subtitle_shape.top > title_shape.top:
                    found_in_subtitle_position = True
            elif subtitle_shape:  # Found subtitle but no clear title
                found_in_subtitle_position = True

        if found_in_subtitle_position:
            return "Subtitle text found in appropriate position below title", 1.0
        else:
            return "Subtitle text not found in expected position or context", 0.0

    except Exception as e:
        return f"Error checking subtitle position: {str(e)}", 0.0

