def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        original_prs = Presentation(original_ppt_path)
        modified_prs = Presentation(modified_ppt_path)

        target_text = "Philippine History: An Educational Overview"
        excessive_changes = False
        changes_count = 0

        # Compare slide by slide
        min_slides = min(len(original_prs.slides), len(modified_prs.slides))

        for i in range(min_slides):
            orig_slide = original_prs.slides[i]
            mod_slide = modified_prs.slides[i]

            # Get all text from both slides
            orig_texts = []
            mod_texts = []

            for shape in orig_slide.shapes:
                if hasattr(shape, 'text'):
                    orig_texts.append(shape.text.strip())

            for shape in mod_slide.shapes:
                if hasattr(shape, 'text'):
                    mod_texts.append(shape.text.strip())

            # Count text differences
            for orig_text in orig_texts:
                if orig_text and orig_text not in mod_texts:
                    # Check if this was replaced by our target text
                    if target_text not in mod_texts:
                        changes_count += 1

            for mod_text in mod_texts:
                if mod_text and mod_text not in orig_texts:
                    # This is a new text, acceptable if it's our target
                    if mod_text != target_text:
                        changes_count += 1

        # Allow for 1-2 changes (original subtitle removal + new subtitle addition)
        if changes_count <= 2:
            return f"Minimal content changes detected ({changes_count} changes), appropriate for subtitle edit", 1.0
        else:
            return f"Excessive content changes detected ({changes_count} changes), more than expected for subtitle edit", 0.3

    except Exception as e:
        return f"Error checking content changes: {str(e)}", 0.5
